import React from "react";
import Sidebar from "./Sidebar";
import { useTheme } from "../context/ThemeContext"; // ✅ IMPORTANTE: Importar el hook

/**
 * Layout Component: 
 * Actúa como el contenedor principal de la aplicación.
 * Mantiene el Sidebar fijo a la izquierda y el contenido dinámico a la derecha.
 */
export default function Layout({ children }) {
  return (
    <div style={{ display: "flex", minHeight: "100vh" }}>
      {/* Barra lateral fija */}
      <Sidebar />

      {/* Área de contenido principal */}
      <main
        style={{
          marginLeft: "250px", // Debe coincidir con el ancho de tu Sidebar
          padding: "30px",
          width: "calc(100% - 250px)", // Ajusta el ancho restando el Sidebar
          background: "#f4f7f6", // Un gris más suave y profesional
          transition: "margin 0.3s ease", // Por si luego decides hacer el sidebar colapsable
        }}
      >
        {/* Aquí es donde React renderizará tus vistas (Productos, Ventas, etc.) */}
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          {children}
        </div>
      </main>
    </div>
  );
}
